export const extendedPosts = [
  { slug: 'youtube-kids-vs-youtube-which-is-safer', title: 'YouTube Kids vs YouTube: Which Is Safer for Your Child?', date: 'April 1, 2026', readTime: 7, category: 'Parent Guidance', excerpt: 'Most parents assume YouTube Kids is completely safe. The reality is more nuanced.', metaDescription: 'YouTube Kids vs YouTube: the real differences, remaining risks, and how to set it up properly for your child.', content: `<p>When YouTube Kids launched, many parents breathed a sigh of relief. A version of YouTube designed for children, with curated content and no comments section. The reality is more complicated.</p><h2>What YouTube Kids Actually Is</h2><p>YouTube Kids is a separate app that pulls content from YouTube but applies automated filters. It has no comments section, no recommendation feeds based on watch history, and content is loosely categorised by age group. However, it is not a hand-reviewed library. Content passes through automated filters, and those filters are imperfect. Researchers and parents have documented inappropriate content appearing on YouTube Kids.</p><h2>Key Differences</h2><p><strong>Content filtering:</strong> YouTube Kids uses automated filtering. Regular YouTube is entirely unfiltered unless Restricted Mode is on. Neither system is perfect, but YouTube Kids catches significantly more inappropriate content for the youngest age groups.</p><p><strong>The algorithm:</strong> Regular YouTube's recommendation algorithm leads children down rabbit holes of increasingly extreme content. YouTube Kids' recommendations are more constrained.</p><p><strong>Search:</strong> On YouTube Kids, you can turn off search entirely so your child can only watch what you have approved. This is the single most powerful setting on the platform — enable it for children under eight.</p><p><strong>Comments:</strong> YouTube Kids has no comments. Regular YouTube's comments section exposes children to adult content and occasionally predatory contact. This alone makes YouTube Kids significantly safer for young children.</p><h2>Setting Up YouTube Kids Properly</h2><p>Choose a content level: Preschool, Younger, Older, or Approve Content Yourself. Turn off search for children under eight. Set a daily timer under Settings → Timer. Review Watch History regularly — it tells you what your child is engaging with and opens natural conversation.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Growing Minds</strong> course covers age-appropriate online safety, how to set up devices safely, and how to build healthy digital habits from the start.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'roblox-safety-guide-for-parents', title: 'Roblox Safety Guide for Parents: What You Need to Know', date: 'April 1, 2026', readTime: 8, category: 'Gaming Safety', excerpt: 'Roblox is one of the most popular platforms for children worldwide — and one of the least understood by parents.', metaDescription: 'Complete Roblox safety guide for parents. Understand how Roblox works, the real risks, and how to use parental controls to keep your child safe.', content: `<p>Roblox has over 70 million daily users and is one of the most popular platforms for children aged six to sixteen worldwide. Yet many parents have only a vague sense of what it is. It is not a single game — it is a platform hosting millions of user-created games.</p><h2>What Roblox Actually Is</h2><p>Think of Roblox less like a video game and more like a gaming social network. Children play user-created games, customise their avatar, earn and spend virtual currency (Robux), chat with other players, and join groups. The platform is free to play but Robux can be purchased.</p><h2>The Real Safety Concerns</h2><p><strong>Chat and contact from strangers.</strong> Roblox has a chat function operating both within games and outside them. Children can receive friend requests and messages from complete strangers. Grooming-style contact and attempts to move conversations off-platform have been documented.</p><p><strong>User-created content.</strong> Because anyone can create games on Roblox, content standards vary enormously. Some user-created games contain violence, sexual themes, or horror content not appropriate for young children.</p><p><strong>Robux spending.</strong> Children can spend significant amounts if purchases are not locked behind parental approval.</p><p><strong>Scams.</strong> "Free Robux" scams are ubiquitous. These phishing attempts trick children into giving up account credentials. Children should know categorically that free Robux offers are always scams.</p><h2>Safety Settings That Matter</h2><p>Go to your child's account settings: Under Privacy, set Who can chat with me? to Friends. Under Account Restrictions (for children under 13), enable restrictions to limit chat to a preset safe list. Set up a PIN under Security → Account PIN to prevent your child changing safety settings. For spending, set monthly Robux budget and require approval for purchases.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Growing Minds</strong> course covers gaming platforms including Roblox in depth — giving parents the knowledge to set up these platforms safely.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'online-safety-for-toddlers-and-preschoolers', title: 'Online Safety for Toddlers and Preschoolers: A Parent\'s Guide', date: 'April 1, 2026', readTime: 6, category: 'Parent Guidance', excerpt: 'Even toddlers are online now. Here is how to make digital experiences safe and developmentally appropriate for the youngest children.', metaDescription: 'Online safety for toddlers and preschoolers. Set up devices safely, choose age-appropriate content, and build healthy digital habits from the very start.', content: `<p>Children are encountering screens earlier than ever. Tablets, smart TVs, smartphones, and voice assistants mean that even toddlers interact with the internet long before they understand what it is.</p><h2>The Core Principle: Supervised, Purposeful, Limited</h2><p>For children under five, every principle of safe online use comes down to three words. Screens should be used with adult involvement wherever possible, for a specific reason, and for a defined amount of time. Unsupervised, open-ended screen access for toddlers serves neither their development nor their safety.</p><h2>Setting Up Devices Safely</h2><p><strong>Tablets:</strong> Set up a child profile rather than letting your child use your account. On iPad, use Screen Time to enable content restrictions, time limits, and app approvals. On Android tablets, use Google Kids Space or a supervised Family Link account.</p><p><strong>Smart TVs:</strong> Most smart TVs have a Kids Mode. Enable these and use dedicated children's apps — BBC iPlayer Children's, Netflix Kids profile, Disney+. YouTube on a smart TV is not appropriate for unsupervised use by young children.</p><h2>Building Good Habits Early</h2><p>The habits children build around screens at two and three tend to persist. Establishing screen-free mealtimes, a consistent routine around screen time, and the expectation that screens go off without a tantrum when the time is up — these lay the foundation for the more complex conversations about online safety that come in a few years.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Growing Minds</strong> course covers the full journey from first screens to teenage social media.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'online-safety-for-university-students', title: 'Online Safety for University Students: What No One Tells You', date: 'April 1, 2026', readTime: 7, category: 'Young Adult Safety', excerpt: 'University is the first time many young people manage their own digital life without parental oversight. Here are the risks they face.', metaDescription: 'Online safety guide for university students. Protect yourself from scams, identity theft, and social media risks as you navigate life independently.', content: `<p>University is the first time many young people manage their own digital life entirely. New devices, new accounts, new networks — and new risks. Young adults at university are disproportionately targeted by online scams, identity theft, and social media fraud.</p><h2>The Scams Targeting Students</h2><p><strong>Student loan and finance scams.</strong> Every year around the time student finance payments land, scammers send convincing messages claiming to be from Student Finance England, asking students to verify bank details. Student Finance will never contact you by text asking for banking details. Always log in directly at the official website — never via a link in a message.</p><p><strong>Accommodation deposit scams.</strong> Fake landlords advertising non-existent properties target students searching for housing. Always verify a landlord exists, use a reputable letting agency, and never pay a deposit without seeing the property and verifying the landlord's identity.</p><p><strong>Job scams.</strong> Part-time job offers that seem unusually well-paid — mystery shopping roles, brand ambassador opportunities — are often fronts for money muling or data harvesting.</p><h2>Protecting Your Digital Identity</h2><p>Use a password manager (Bitwarden is free) to generate and store strong unique passwords for every account. Enable two-factor authentication on every account that supports it. Be thoughtful about public WiFi — access banking on your phone's mobile data instead.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Nest Breaking</strong> course is built specifically for young adults stepping into independence — covering digital risks from scam awareness to identity protection.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'dating-app-safety-young-adults', title: 'Dating App Safety: What Young Adults Need to Know Before Swiping', date: 'April 1, 2026', readTime: 8, category: 'Young Adult Safety', excerpt: 'Dating apps are a normal part of modern life for young adults. But they carry real risks that go beyond the obvious.', metaDescription: 'Dating app safety guide for young adults. How to protect yourself on Tinder, Bumble, Hinge — privacy settings, meeting safely, and spotting fake profiles.', content: `<p>Dating apps are used by millions of young adults and are a completely normal part of modern dating. But they carry risks many users — particularly first-timers — are not fully aware of.</p><h2>What You Share Without Realising</h2><p>Most dating apps use your location to show matches nearby. The precision of this information matters — some apps have previously exposed near-exact coordinates. Review privacy settings on every app. Turn off precise location where the option exists. Think carefully about what your photos reveal — a photo taken at home might show your street through a window, or your gym through clothing.</p><h2>Spotting Fake Profiles and Scams</h2><p>Romance scams — where a fake persona builds a relationship over weeks or months then requests money — are professional and patient. Red flags: too attractive and too interested, unwilling to video call despite extended messaging, a reason they cannot meet in person, and eventually a financial ask however it is framed. Reverse image search any photo you are unsure about.</p><h2>Meeting Safely for the First Time</h2><p>Always meet in a public place. Tell a friend where you are going and when you expect to be back. Share your live location with a trusted person for the duration. Do not get into someone's car on a first meeting. Keep your drink with you at all times. Trust your instincts — if something feels wrong, it is perfectly reasonable to end the conversation.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Nest Breaking</strong> course covers the full range of digital risks young adults face — including dating apps, social media privacy, and how to recognise online manipulation.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'romance-scams-how-to-recognise-them', title: 'Romance Scams: How to Recognise Them Before It\'s Too Late', date: 'April 1, 2026', readTime: 7, category: 'Young Adult Safety', excerpt: 'Romance scams are among the most financially and emotionally devastating forms of fraud. Here is how they work and how to spot them.', metaDescription: 'How to recognise and avoid romance scams online. Learn the warning signs, how scammers operate, and what to do if you think you\'re being targeted.', content: `<p>Romance scams cause more financial loss than almost any other form of online fraud, and their emotional impact goes far beyond money. Understanding how they work is the best protection.</p><h2>How Romance Scams Work</h2><p>The process is methodical and patient. A scammer creates a convincing fake profile — often using stolen photos of an attractive, successful-looking person, typically in a profession that explains why they cannot meet (military, offshore oil rig, doctor abroad). They connect on dating apps, social media, or messaging apps.</p><p>Phase one is relationship building — sometimes weeks or months of daily messaging, learning everything about the target, expressing deep connection. Phase two is a crisis story requiring money: a medical emergency, business opportunity, fee to release funds, a plane ticket to visit. Phase three is escalation — once someone has sent money once, requests continue and grow.</p><h2>Warning Signs</h2><p>Someone too perfect and too interested. A relationship escalating too quickly in intensity. Consistent unwillingness to video call. Inability to meet despite extended contact. A story that conveniently needs money. Requests for wire transfers, cryptocurrency, or gift cards — payment methods impossible to reverse.</p><h2>What to Do</h2><p>Reverse image search their photos. Search their name alongside "scam" or "fraud." Ask to video call and observe the reaction. If you have already sent money, contact your bank immediately. Report to your local fraud reporting service.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Nest Breaking</strong> and <strong>Aging Wisdom</strong> courses both cover romance scams — helping you recognise the signs before real harm is done.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'public-wifi-dangers', title: 'The Dangers of Public WiFi — and How to Protect Yourself', date: 'April 1, 2026', readTime: 6, category: 'Travel Safety', excerpt: 'Public WiFi in coffee shops, hotels, and airports is convenient. It is also one of the easiest ways for hackers to intercept your data.', metaDescription: 'Public WiFi dangers explained. What risks exist on public networks, what attackers can see, and how to protect yourself when using WiFi away from home.', content: `<p>Free public WiFi is one of the most convenient features of modern travel. The risks are real but often overstated, and the protections are simple.</p><h2>What Can Go Wrong on Public WiFi</h2><p><strong>Man-in-the-middle attacks.</strong> On an unencrypted network, a skilled attacker can potentially intercept data you send and receive. This matters most for unencrypted HTTP connections — increasingly rare as most sites now use HTTPS.</p><p><strong>Evil twin networks.</strong> An attacker can set up a hotspot with the same name as a legitimate network and wait for devices to connect. All your traffic routes through their device. Always confirm the correct network name with venue staff before connecting.</p><h2>How to Protect Yourself</h2><p><strong>Use a VPN.</strong> A Virtual Private Network encrypts all your traffic before it leaves your device. ProtonVPN offers a good free option. Turn it on before connecting to any public network.</p><p><strong>Use mobile data for sensitive tasks.</strong> If you need to access your bank while out, your phone's mobile data is significantly more secure than any public WiFi.</p><p><strong>Verify the network name.</strong> Ask venue staff for the correct WiFi name before connecting. If the network has no password, be more cautious about what you do on it.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Roaming Free</strong> course covers digital security for people on the move — including public WiFi risks, VPN setup, and keeping accounts secure while travelling.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'digital-security-when-travelling-abroad', title: 'Digital Security Essentials for International Travel', date: 'April 1, 2026', readTime: 8, category: 'Travel Safety', excerpt: 'Travelling internationally brings specific digital risks that most people never prepare for. Here is everything you need to do.', metaDescription: 'Complete guide to digital security when travelling internationally. Protect your devices, accounts, and data before, during, and after your trip abroad.', content: `<p>International travel creates specific digital security challenges. A little preparation makes a significant difference.</p><h2>Before You Travel</h2><p>Back everything up before you leave. Enable full-device encryption. Update all software — travel is not the time to have pending security updates. Set up a travel notification with your bank so foreign transactions do not trigger fraud blocks.</p><h2>While Travelling</h2><p>Use a VPN on all public networks — hotel WiFi, airport WiFi, café WiFi. Be cautious about charging at public USB charging stations. "Juice jacking" — where malicious charging stations transfer malware — has been documented at airports. Use your own charger or a USB data blocker.</p><p>Use your phone's mobile data for banking rather than public WiFi.</p><h2>If Something Goes Wrong</h2><p>If your phone is stolen: immediately use Find My or Find My Device to lock and track it. Contact your mobile provider to block the SIM. Change passwords for your most important accounts immediately from a secure device.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Roaming Free</strong> course is a complete digital safety guide for people who travel — covering everything from pre-trip preparation to handling incidents abroad.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'online-travel-scams', title: 'Online Travel Scams: How to Spot Them and Stay Safe', date: 'April 1, 2026', readTime: 7, category: 'Travel Safety', excerpt: 'Travel scams have moved online. From fake booking sites to phishing visa applications, here is what to watch for.', metaDescription: 'Common online travel scams explained. Fake booking sites, visa scams, holiday rental fraud, and phishing — how to protect your money when booking travel.', content: `<p>Travel is one of the highest-value categories of online purchase, making it a lucrative target for scammers. Every stage of travel planning has associated scams.</p><h2>Fake Booking Sites</h2><p>Fraudulent websites mimic legitimate travel platforms and appear in Google search results. The booking completes, you receive a confirmation, and only when you arrive do you discover the booking was never made. Always book through official websites. Be suspicious of deals significantly better than everywhere else.</p><h2>Visa and Entry Requirement Scams</h2><p>Scam websites charge inflated fees to "help" travellers apply for visas, exploiting confusion around official processes. Always apply through official government websites. For the US ESTA, the only legitimate site is esta.cbp.dhs.gov.</p><h2>Holiday Rental Fraud</h2><p>Properties advertised informally are frequently fake — photos are stolen from legitimate listings, but the "landlord" has no connection to the property. Use established platforms (Airbnb, Vrbo) that offer buyer protection. For direct bookings, verify the property exists through Google Maps Street View.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Roaming Free</strong> course covers the full range of digital risks for travellers — from booking scams to device security.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'vpn-what-travellers-need-to-know', title: 'VPNs for Travellers: What They Do, What They Don\'t, and Which to Use', date: 'April 1, 2026', readTime: 6, category: 'Travel Safety', excerpt: 'You have probably heard you should use a VPN when travelling. Here is a clear, honest explanation.', metaDescription: 'VPN guide for travellers. What a VPN does, how it protects you on public WiFi, and the best free and paid options for international travel.', content: `<p>A VPN creates an encrypted tunnel between your device and a server operated by the VPN company. All your internet traffic flows through this tunnel — anyone monitoring the network sees only that you are connected to a VPN server, not which sites you visit.</p><h2>What a VPN Does Not Do</h2><p>A VPN does not make you anonymous. The VPN company itself can see your traffic. It does not protect you from phishing, malware, or scams. It does not protect data stored on your device.</p><h2>Which VPN to Use</h2><p><strong>Free options:</strong> ProtonVPN is the most trustworthy free VPN — genuine no-logs policy, operated by ProtonMail's makers. Windscribe also has a reasonable free tier. Avoid free VPNs from unknown providers — many log and sell your browsing data, defeating the purpose entirely.</p><p><strong>Paid options:</strong> Mullvad (privacy-focused), ExpressVPN (fast and reliable), NordVPN (well-known) — all around a few dollars per month.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Roaming Free</strong> course walks you through every aspect of staying secure online when you travel — including a practical VPN setup guide.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'online-scams-targeting-older-people', title: 'Online Scams Targeting Older People: How to Spot Them and Stay Safe', date: 'April 1, 2026', readTime: 8, category: 'Older Adult Safety', excerpt: 'Older adults lose more money to online fraud than any other age group. Not because they are less intelligent — but because scammers target them specifically.', metaDescription: 'Online scams targeting older people explained. The most common types, why they are so effective, and practical steps to protect yourself and your family.', content: `<p>Financial fraud targeting older adults has reached epidemic proportions. Older adults are not more gullible — they are more systematically targeted. Statistically, older adults are more likely to own their homes, have savings, answer the phone, and have less familiarity with newer forms of digital deception.</p><h2>The Most Common Scams</h2><p><strong>Authorised push payment fraud.</strong> You receive a call from someone claiming to be your bank or the police, telling you to move money to a "safe account." Banks and police will never ask you to move money. If you receive this call, hang up, wait ten minutes, and call your bank on the number on the back of your card.</p><p><strong>Tech support scams.</strong> A pop-up appears claiming your computer is infected, or someone calls claiming to be from Microsoft. They gain remote access and steal banking credentials. Never allow remote access to anyone who contacts you first.</p><p><strong>Investment scams.</strong> Advertisements offering unusually high returns on cryptocurrency or foreign exchange. Check any investment platform at your country's financial regulator before depositing money.</p><h2>Practical Protections</h2><p>Register with the Telephone Preference Service. Install a call blocker. Never give remote access to your computer to anyone who contacts you first. Never move money at the request of someone who contacts you unexpectedly.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Aging Wisdom</strong> course covers every major type of fraud in depth, with practical guidance on how to recognise and respond to each one.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'how-to-recognise-phishing-emails', title: 'How to Recognise Phishing Emails: A Practical Guide', date: 'April 1, 2026', readTime: 7, category: 'Older Adult Safety', excerpt: 'Phishing emails are the most common form of online fraud. They have become far more convincing than most people realise.', metaDescription: 'How to recognise phishing emails. Learn the signs of a phishing attack, what to look for, and what to do if you click a phishing link.', content: `<p>Phishing is the most widespread form of cybercrime globally. Modern phishing emails can be nearly indistinguishable from legitimate ones.</p><h2>How to Spot Them</h2><p><strong>Check the sender's email address carefully.</strong> Not the display name — the actual address. Legitimate organisations send from their own domain. A message appearing to come from "Lloyds Bank" but sent from lloyds-secure@account-verify.net is phishing.</p><p><strong>Hover over links before clicking.</strong> Before clicking any link, hover to see where it actually leads. A link claiming to take you to your bank but showing a different domain is a phishing link.</p><p><strong>Look for urgency and pressure.</strong> Phishing emails almost always create urgency — your account will be closed, act now. Legitimate organisations give you time.</p><p><strong>Be suspicious of unexpected attachments.</strong> A legitimate bank will almost never send an unsolicited attachment. If you receive an unexpected email with an attachment, do not open it without verifying through a different channel.</p><h2>What to Do If You Have Clicked</h2><p>If you entered login details: go directly to the real website and change your password immediately. If banking: call your bank straight away. Report phishing emails through your email provider's abuse reporting feature.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Aging Wisdom</strong> course covers phishing and email fraud in depth — with real examples and clear guidance.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'online-banking-safety-guide', title: 'How to Bank Safely Online: A Complete Guide', date: 'April 1, 2026', readTime: 7, category: 'Older Adult Safety', excerpt: 'Online banking is convenient, secure — and a target for fraud. Here is everything you need to know to protect your money.', metaDescription: 'Complete guide to safe online banking. Protect your accounts, spot banking fraud, and know what to do if something goes wrong.', content: `<p>Online banking is the primary target of financial fraud. The good news: it is genuinely safe when used correctly, and the protective measures are straightforward.</p><h2>Setting Up Your Account Securely</h2><p>Use a strong, unique password for banking — not used for any other account. Enable two-factor authentication. Set up transaction alerts so you know immediately if any transaction occurs that you did not make.</p><h2>Logging In Safely</h2><p>Always type your bank's address directly into your browser rather than clicking a link. The address should start with https://. Never log into your bank on a public computer or public WiFi — use your phone's mobile data instead.</p><h2>Recognising Banking Fraud Attempts</h2><p>Your bank will never call, text, or email asking for your full PIN, full password, or asking you to move money to a "safe account." These are always fraud. If you receive such a call, hang up. Wait ten minutes and call the number on the back of your card.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Aging Wisdom</strong> course covers online banking safety in full — with clear, practical guidance for confident and secure banking.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'safe-online-shopping-guide', title: 'How to Shop Online Safely: Avoiding Scams and Protecting Your Money', date: 'April 1, 2026', readTime: 7, category: 'Older Adult Safety', excerpt: 'Online shopping is one of the most convenient things about the internet. It is also where significant fraud happens.', metaDescription: 'Safe online shopping guide. Spot fake shops, protect your payment details, and know what to do if you\'ve been scammed by an online retailer.', content: `<p>Online shopping fraud has multiple forms — from fake websites to counterfeit goods to payment data theft. Understanding them puts you in control.</p><h2>Identifying Legitimate Online Shops</h2><p>Check the web address — it should start with https://. Look for real contact details (physical address, phone number). Check reviews on Trustpilot and Google Reviews. Be suspicious of prices that are significantly lower than everywhere else.</p><h2>Paying Safely</h2><p>Pay by credit card where possible. Credit card payments may be protected under your country's consumer protection laws. Avoid bank transfer payments for online shopping — transfers are hard to reverse and offer no consumer protection. Never save payment details on sites you are not completely confident in.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Aging Wisdom</strong> course covers safe online shopping in detail — how to verify retailers, protect payment details, and what to do when things go wrong.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'phone-and-text-scams', title: 'Phone and Text Scams: What They Look Like and What to Do', date: 'April 1, 2026', readTime: 6, category: 'Older Adult Safety', excerpt: 'Scam calls and texts have become more sophisticated and more frequent. Here is how to recognise them.', metaDescription: 'Guide to phone and text scams. Recognise smishing, vishing, and common scam tactics. What to do when you receive a suspicious call or text.', content: `<p>Scam phone calls and text messages have become considerably more sophisticated in recent years, convincingly impersonating banks, tax authorities, and delivery companies.</p><h2>Scam Phone Calls (Vishing)</h2><p>Scammers call pretending to be your bank, tax authorities, police, or Microsoft. They can spoof caller ID to make the call appear to come from a legitimate number. The key rules: no legitimate bank, police force, or government agency will ever ask you to move money to a safe account. No legitimate tech company will call you out of the blue about your computer. If an unexpected call asks for personal information or money, hang up.</p><h2>Scam Text Messages (Smishing)</h2><p>Text scams impersonate delivery companies, banks, tax authorities, and retail companies. Signs: a link not matching the organisation's real web address, urgency to act immediately, requests for payment or personal details. Never click links in texts from organisations you did not initiate contact with.</p><h2>Reporting and Reducing Scam Contact</h2><p>Report scam texts through your mobile provider. Report scam calls to your local fraud reporting service. Register with the Telephone Preference Service. Install a call-blocking app like Hiya or Truecaller.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Aging Wisdom</strong> course covers phone and text fraud in full — with real examples and clear guidance on protecting yourself and your family.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'social-media-safety-for-older-adults', title: 'Social Media Safety for Older Adults: Getting Started Safely', date: 'April 1, 2026', readTime: 7, category: 'Older Adult Safety', excerpt: 'Social media can be a wonderful way to stay connected. It also carries risks worth understanding before you dive in.', metaDescription: 'Social media safety guide for older adults. Use Facebook, WhatsApp and other platforms safely, protect your privacy, and avoid the most common scams.', content: `<p>Social media offers real benefits for older adults — staying connected with family, joining communities, finding information. It also carries risks proportionate to the information you share.</p><h2>Privacy Settings First</h2><p>Before anything else, configure privacy settings. On Facebook: Settings → Privacy → change Who can see your future posts? to Friends. On Instagram: make your account private. These prevent strangers from seeing your personal information, photos, and connections.</p><h2>What Not to Share</h2><p>Never share your full date of birth publicly — combined with your name and address it can be used for identity theft. Never post photos of cards, passports, or documents. Be cautious posting when away from home. Do not share your daily routine publicly.</p><h2>WhatsApp Safety</h2><p>Be cautious in group chats — messages are frequently forwarded without context and misinformation spreads rapidly. Never send money or personal information in response to a WhatsApp message without verifying through a phone call to the person you know.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Aging Wisdom</strong> course is a complete guide to using the internet safely as an older adult.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'video-calling-safety-zoom-whatsapp', title: 'Video Calling Safety: Protecting Your Privacy on Zoom, WhatsApp and More', date: 'April 1, 2026', readTime: 6, category: 'Older Adult Safety', excerpt: 'Video calling has transformed how we stay in touch. But it introduces privacy considerations worth understanding.', metaDescription: 'Video calling safety guide. Use Zoom, WhatsApp video, FaceTime and other platforms safely. Protect your privacy and avoid video call scams.', content: `<p>Video calling has become one of the most valuable digital tools for staying in touch. Understanding a few key principles makes it safe.</p><h2>Choosing the Right Platform</h2><p>WhatsApp and FaceTime offer end-to-end encrypted calls. Zoom and Microsoft Teams are better for group calls. For calling family and friends, WhatsApp or FaceTime are usually the simplest and most private.</p><h2>Video Call Scams</h2><p>Scammers sometimes use video calls as part of manipulation. The "sextortion" scam uses a brief video call to capture footage used as blackmail. If someone you have been messaging consistently refuses to video call, treat this as a significant warning sign of a romance scam.</p><h2>What Others Can See</h2><p>Before joining a video call, be conscious of what is visible in your background. If your home address is visible on letters, or valuable items are clearly visible, consider using a virtual background or repositioning your camera.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Aging Wisdom</strong> course covers digital communication tools for older adults — including video calling, messaging apps, and using them safely and confidently.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'how-to-create-strong-passwords', title: 'How to Create Strong Passwords — and Why It Matters More Than You Think', date: 'April 1, 2026', readTime: 6, category: 'Digital Security', excerpt: 'Weak passwords are the single most common cause of account takeovers. Here is how to create passwords that actually protect you.', metaDescription: 'How to create strong passwords and manage them effectively. What makes a password secure, why password managers matter, and how to protect all your accounts.', content: `<p>Weak and reused passwords are the most common cause of account takeovers, and account takeovers are the gateway to most forms of online fraud.</p><h2>What Makes a Password Strong</h2><p>Length matters more than complexity. A sixteen-character password using common words is harder to crack than an eight-character one with symbols. The ideal password is long (at least twelve characters), random (not based on dictionary words or names), and unique (not used on any other account).</p><h2>Why Password Reuse Is So Dangerous</h2><p>When companies are hacked, stolen email and password combinations are sold and traded online. Criminals run these against major websites automatically. If you use the same password everywhere, a breach at one small site can give access to everything. Check haveibeenpwned.com to see if your email has appeared in known breaches.</p><h2>The Solution: A Password Manager</h2><p>A password manager generates, stores, and fills in strong unique passwords for every account. You only need to remember one master password. Bitwarden is free and excellent. 1Password and Dashlane are excellent paid options.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our courses cover digital security fundamentals — including passwords, account security, and protecting yourself online for every age group.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'two-factor-authentication-explained', title: 'Two-Factor Authentication: What It Is and Why Everyone Should Use It', date: 'April 1, 2026', readTime: 6, category: 'Digital Security', excerpt: 'Two-factor authentication is the single most effective thing you can add to your accounts to prevent them being hacked.', metaDescription: 'Two-factor authentication explained simply. What 2FA is, why it matters, the types available, and how to enable it on your most important accounts.', content: `<p>Two-factor authentication (2FA) is the single most effective security measure you can add to your online accounts. It prevents account takeover even when someone has your password.</p><h2>What Is Two-Factor Authentication?</h2><p>Normal login requires one thing: your password. 2FA adds a second requirement — a code sent to your phone, a code generated by an app, or a biometric. Even if a criminal has your password, they cannot get in without your second factor.</p><h2>Authenticator Apps</h2><p>Apps like Google Authenticator, Microsoft Authenticator, or Authy generate time-based six-digit codes that change every thirty seconds. These are more secure than SMS codes and cannot be intercepted through SIM swapping.</p><h2>How to Turn It On</h2><p>For most accounts: Settings → Security → Two-Factor Authentication. Priority accounts: your email account (it is the master key — password resets go there), banking, social media, and any account holding payment information.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Account security is a core part of every course at HomeSafeEducation — for every age and life stage.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'how-to-spot-a-fake-website', title: 'How to Spot a Fake Website Before It\'s Too Late', date: 'April 1, 2026', readTime: 6, category: 'Digital Security', excerpt: 'Fake websites have become alarmingly convincing. Here is a practical checklist for verifying any website before you enter your details.', metaDescription: 'How to spot a fake or scam website. Check the URL, verify the organisation, and protect yourself from phishing and fraud sites.', content: `<p>Fake websites impersonating legitimate shops, banks, and organisations are one of the most common tools of online fraud. Modern fake sites can be pixel-perfect copies of the real thing.</p><h2>Check the URL Carefully</h2><p>Look at the domain name — the core part of the address before any slashes. Legitimate websites have simple, recognisable domain names. Scam sites use variations like adding extra words or misspelling the company name. Always type the address directly rather than clicking links, and check the address bar carefully before entering any information.</p><h2>Search for the Organisation Independently</h2><p>Before entering details into an unfamiliar site, search for the organisation's name plus "review" or "scam." Check Trustpilot. Search for the company in your country's business registry.</p><h2>Trust Your Instincts</h2><p>If something feels slightly off — the language is wrong, prices are suspiciously low, contact details do not check out — trust that feeling and verify before proceeding.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our courses cover online fraud and scam awareness comprehensively — giving everyone in your family the tools to navigate the internet safely.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'what-to-do-if-scammed-online', title: 'I\'ve been Online: What Do I Do Now?', date: 'April 1, 2026', readTime: 7, category: 'Digital Security', excerpt: 'Being scammed online can be frightening. Here is exactly what to do — step by step — to minimise the damage.', metaDescription: 'What to do after being scammed online. Stop further damage, report the scam, and maximise the chance of recovering what you lost.', content: `<p>Discovering you have been scammed online is deeply unpleasant. It happens to people of all ages and all levels of digital literacy. Acting quickly makes a significant difference.</p><h2>Step 1: Stop Any Further Payments</h2><p>If someone has remote access to your device, disconnect it from the internet immediately. If you have an ongoing instruction to transfer money, contact your bank to cancel it.</p><h2>Step 2: Contact Your Bank</h2><p>Call your bank using the number on the back of your card. Tell them exactly what happened. Banks are typically required to reimburse victims of authorised push payment fraud in most circumstances. The faster you report, the better.</p><h2>Step 3: Change Your Passwords</h2><p>If you gave login details to any account, change those passwords immediately from a secure device. Enable two-factor authentication on any account where it was not already on.</p><h2>Step 4: Report It</h2><p>Report to your local fraud reporting service. Report the fraudulent account through the relevant platform. For large amounts, contact your local police non-emergency line.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Aging Wisdom</strong> and <strong>Nest Breaking</strong> courses provide comprehensive guidance on protecting yourself going forward after fraud.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'protecting-your-identity-online', title: 'How to Protect Your Identity Online: A Complete Guide', date: 'April 1, 2026', readTime: 7, category: 'Digital Security', excerpt: 'Identity theft can take years to fully resolve. Here is how to protect your personal information and what to do if your identity is stolen.', metaDescription: 'Complete guide to protecting your identity online. Prevent identity theft, recognise the warning signs, and know what to do if your identity has been stolen.', content: `<p>Identity theft — where someone uses your personal information to open accounts or commit fraud in your name — is one of the most disruptive forms of cybercrime. Prevention is far easier than recovery.</p><h2>Where Your Information Is at Risk</h2><p>Data breaches, social media over-sharing, phishing, and physical mail all put your personal information at risk. Check haveibeenpwned.com to see if your email has appeared in known breaches. Review what you have made public on every social media platform.</p><h2>Monitoring for Warning Signs</h2><p>Check your credit report regularly through Experian, Equifax, or TransUnion. Signs your identity may have been stolen include: unexpected financial statements, calls from debt collectors about accounts you did not open, or being turned down for credit unexpectedly.</p><h2>If Your Identity Is Stolen</h2><p>Contact all affected financial institutions immediately. Place a fraud marker on your credit file through your country\'s fraud prevention service — this adds a protective registration requiring extra checks for any new credit in your name. Report to your local fraud reporting service.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Identity protection and fraud prevention are covered across our course range — for every age and life stage.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'discord-safety-guide', title: 'Discord Safety: What Parents and Young Adults Need to Know', date: 'April 1, 2026', readTime: 7, category: 'Young Adult Safety', excerpt: 'Discord is one of the most popular communication platforms for young people — and one of the least understood by parents.', metaDescription: 'Discord safety guide for parents and young adults. How Discord works, what the risks are, and how to configure privacy settings.', content: `<p>Discord began as a gaming communication platform but has become one of the most widely used messaging platforms among teenagers and young adults globally.</p><h2>How Discord Works</h2><p>Discord organises communication into servers — communities with channels for text chat, voice chat, and video. Some servers are private (invite only), others are public. Discord also supports direct messages between individuals.</p><h2>The Safety Concerns</h2><p><strong>Contact from strangers.</strong> Discord users can receive direct messages from strangers, and public servers can expose young people to adults with harmful intentions. Grooming has occurred through Discord, particularly in gaming communities where adults target younger users.</p><p><strong>Age-restricted content.</strong> Discord hosts age-restricted servers containing explicit content. The age verification process is not robust, and young people regularly access content intended for adults.</p><h2>Privacy Settings to Configure</h2><p>Go to User Settings → Privacy and Safety: set Who can add you as a friend? to Friends of Friends or No one for younger users. Enable Scan messages from everyone for explicit images. Turn off Allow direct messages from server members — this prevents strangers from DMing you directly.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Nest Breaking</strong> course covers the platforms young adults use most — including Discord and gaming communities — with practical guidance on staying safe.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'digital-safety-for-remote-workers', title: 'Digital Safety for Remote Workers: Protecting Yourself and Your Employer', date: 'April 1, 2026', readTime: 7, category: 'Young Adult Safety', excerpt: 'Remote working has created new digital security challenges that employees often do not receive adequate guidance on.', metaDescription: 'Digital safety guide for remote workers. Protect your home network, work devices, and company data while working from home or public spaces.', content: `<p>The shift to remote working has significantly expanded the attack surface available to cybercriminals. Much of the security responsibility has quietly transferred to individual employees.</p><h2>Securing Your Home Network</h2><p>Change the default admin password on your home router. Set your WiFi to WPA3 encryption. Keep router firmware updated. Consider a separate WiFi network for work devices — this isolates your work laptop from other home devices that may be less secure.</p><h2>Working in Public Spaces</h2><p>Use a VPN when working on public WiFi. Be aware of visual privacy — shoulder surfing is a real threat. Consider a privacy screen filter for regular public workers. Be careful with voice — discussing sensitive information in a public space is a data protection risk.</p><h2>Phishing and Business Email Compromise</h2><p>Remote workers are disproportionately targeted by phishing. Business Email Compromise — attackers impersonating a colleague or client to trick employees into transferring money or sharing sensitive data — is particularly common. Always verify unusual requests through a separate channel before acting.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Nest Breaking</strong> course covers digital safety challenges facing young professionals — including remote work security and scam awareness.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'social-media-safety-while-travelling', title: 'Social Media Safety While on Holiday: What to Post and What Not To', date: 'April 1, 2026', readTime: 6, category: 'Travel Safety', excerpt: 'Sharing your holiday on social media is perfectly normal. But there are specific risks worth being conscious of.', metaDescription: 'Social media safety while travelling. What to share, what not to, and how to protect your home and privacy when posting holiday content.', content: `<p>Sharing holiday photos is natural and enjoyable. A few simple habits meaningfully reduce the associated risks without stopping you from posting.</p><h2>The Risks of Real-Time Posting</h2><p>The primary risk of posting holiday content in real time is advertising that your home is empty. A public post saying "Just landed in Mallorca for two weeks!" is an open invitation to burglars for anyone who can see it and knows your address. For people with private accounts visible only to trusted friends, this risk is relatively low.</p><h2>Location Data in Photos</h2><p>Photos taken on a smartphone embed location data (geotags) by default. Turn off photo geotagging: on iPhone, Settings → Privacy → Location Services → Camera → Never. On Android, Camera → Settings → Location tags → Off.</p><h2>The "Post After" Principle</h2><p>Post holiday content after you return rather than in real time. This means you still share your experiences without broadcasting your absence. Many people find this improves their enjoyment of the holiday too — being less focused on capturing content and more present in the experience.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Roaming Free</strong> course covers digital safety for travellers — including social media, device security, and keeping your home safe while away.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'what-children-should-learn-about-digital-literacy', title: 'What Children Should Know About Digital Literacy by Age 10', date: 'April 1, 2026', readTime: 7, category: 'Digital Education', excerpt: 'Digital literacy is one of the most important skills children need for modern life. Here is what they should know at each stage.', metaDescription: 'Digital literacy milestones for children. What children should understand about the internet, online safety, and digital citizenship by age 10.', content: `<p>Digital literacy has become as fundamental as reading and writing. Yet unlike numeracy, it receives inconsistent attention in both homes and schools.</p><h2>Ages 3–5: First Foundations</h2><p>At this age, build behavioural rather than technical foundations: asking permission before using a device, coming to a grown-up if something makes them feel scared or confused, and understanding that not everything on a screen is real.</p><h2>Ages 5–7: Building Awareness</h2><p>Key concepts: personal information is private (name, address, school not for sharing online), people online may not be who they say they are, and basic rules about permitted apps and websites. Keep the concept of permanent online content simple: "If you drew a picture and left it in the park, anyone walking past could see it."</p><h2>Ages 7–9: Growing Understanding</h2><p>How to tell if online information is reliable, the concept of advertising and sponsored content, digital footprint awareness, and how to report something that upsets them.</p><h2>Age 10: The Pre-Transition Foundation</h2><p>Before secondary school and likely smartphone use: how social media platforms work, the permanence of online content, basic privacy settings, what cyberbullying is, and reporting routes through your country's child protection services.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Growing Minds</strong> course helps parents build age-appropriate digital literacy — giving you knowledge and conversations to prepare your child at every stage.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'protecting-devices-while-travelling', title: 'How to Protect Your Devices When Travelling Abroad', date: 'April 1, 2026', readTime: 6, category: 'Travel Safety', excerpt: 'Your devices carry your entire digital life. Losing them while travelling is disruptive — losing the data can be catastrophic.', metaDescription: 'How to protect your phone and laptop when travelling abroad. Encryption, backup strategies, and what to do if your device is lost or stolen.', content: `<p>Your smartphone and laptop carry banking apps, email, photos, passwords, and contact information. Preparing properly before you leave means even if the worst happens, damage is limited.</p><h2>Physical Security</h2><p>Keep devices in inside pockets or bags worn in front of you in crowded places. Be careful at tourist attractions, on public transport, and at café tables. Never leave devices visible in a parked car.</p><h2>Enable Find My Device</h2><p>Before you travel, make sure Find My is enabled on your iPhone (Settings → [your name] → Find My), or Find My Device on Android. This allows you to locate, lock, and remotely wipe your device if stolen.</p><h2>The Backup Before You Go</h2><p>Back up everything before you travel — iCloud, Google Drive, or an external drive. If your phone is stolen on day one of a three-week trip and you have no backup, you lose three weeks of photos plus your contacts and data.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Roaming Free</strong> course is a complete pre-travel digital security checklist — covering device protection, account security, and what to do in every scenario.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` },
  { slug: 'financial-fraud-online-young-adults', title: 'Financial Fraud Targeting Young Adults: How to Protect Yourself', date: 'April 1, 2026', readTime: 7, category: 'Young Adult Safety', excerpt: 'Young adults are increasingly targeted by financial fraud online. From investment scams to money muling, here is what to watch for.', metaDescription: 'Financial fraud targeting young adults. Recognise investment scams, money muling, and other financial crimes targeting young people online and on social media.', content: `<p>Financial fraud targeting young adults has increased significantly, driven by social media advertising and the growth of cryptocurrency.</p><h2>Investment and Cryptocurrency Scams</h2><p>Social media advertisements for investment schemes — particularly cryptocurrency trading platforms — are one of the most common forms of financial fraud targeting young adults. Impressive claimed returns, screenshots of earnings, urgency around limited availability. In practice: Ponzi schemes, outright theft, or "pig butchering" long-term fraud. Legitimate investment platforms are regulated by your country's financial regulator. your country's financial regulator.</p><h2>Money Muling</h2><p>Money muling — allowing your bank account to be used to transfer stolen funds — is presented as a "money transfer" job, a favour to an online friend, or part of a romance. This is a criminal offence. Consequences include criminal prosecution, criminal record, and permanent banking restrictions.</p><h2>Buy Now Pay Later Scams</h2><p>Scammers impersonating Klarna or Clearpay harvest financial details. Never verify or update payment information by clicking links in messages — always go directly to the official app.</p><div style="background:#F0FDF4;border:2px solid #0EA5A0;border-radius:12px;padding:24px 28px;margin:40px 0;"><h3 style="color:#0B1F3A;margin-top:0;">🛡️ Protect Your Family With Our Online Safety Courses</h3><p style="color:#374151;">Our <strong>Nest Breaking</strong> course covers financial fraud in detail — giving young adults the knowledge to protect their financial wellbeing as they become financially independent.</p><p style="color:#374151;margin-bottom:0;"><a href="/courses" style="color:#0EA5A0;font-weight:600;">Explore Our Courses →</a></p></div>` }
];
